function enrollment_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('enrollment');
	if(!$arrPerm['insert']) return false;

	$data = [
		'date' => Request::dateComponents('date', '1'),
		'full_name' => Request::lookup('full_name', ''),
		'class' => Request::lookup('class', ''),
		'term' => Request::val('term', ''),
		'fees_code' => Request::lookup('fees_code', ''),
	];

	if($data['full_name'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Full name': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['class'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Class': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['term'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Term': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}

	// hook: enrollment_before_insert
	if(function_exists('enrollment_before_insert')) {
		$args = [];
		if(!enrollment_before_insert($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$error = '';
	// set empty fields to NULL
	$data = array_map(function($v) { return ($v === '' ? NULL : $v); }, $data);
	insert('enrollment', backtick_keys_once($data), $error);
	if($error) {
		$error_message = $error;
		return false;
	}

	$recID = db_insert_id(db_link());

	// automatic year if passed as filterer
	if(Request::val('filterer_year')) {
		sql("UPDATE `enrollment` SET `year`='" . makeSafe(Request::val('filterer_year')) . "' WHERE `stid`='" . makeSafe($recID, false) . "'", $eo);
	}

	update_calc_fields('enrollment', $recID, calculated_fields()['enrollment']);

	// hook: enrollment_after_insert
	if(function_exists('enrollment_after_insert')) {
		$res = sql("SELECT * FROM `enrollment` WHERE `stid`='" . makeSafe($recID, false) . "' LIMIT 1", $eo);
		if($row = db_fetch_assoc($res)) {
			$data = array_map('makeSafe', $row);
		}
		$data['selectedID'] = makeSafe($recID, false);
		$args = [];
		if(!enrollment_after_insert($data, getMemberInfo(), $args)) { return $recID; }
	}

	// mm: save ownership data
	set_record_owner('enrollment', $recID, getLoggedMemberID());

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID'))) enrollment_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function enrollment_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);

	// launch requests, asynchronously
	curl_batch($requests);
}

