function enrollment_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('enrollment', $selected_id, 'edit')) return false;

	$data = [
		'date' => Request::dateComponents('date', ''),
		'full_name' => Request::lookup('full_name', ''),
		'class' => Request::lookup('class', ''),
		'term' => Request::val('term', ''),
		'fees_code' => Request::lookup('fees_code', ''),
	];

	if($data['full_name'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Full name': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['class'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Class': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['term'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Term': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('enrollment', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: enrollment_before_update
	if(function_exists('enrollment_before_update')) {
		$args = ['old_data' => $old_data];
		if(!enrollment_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'enrollment', 
		backtick_keys_once($set), 
		['`stid`' => $selected_id], 
		$error_message
	)) {
		echo $error_message;
		echo '<a href="enrollment_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	$eo = ['silentErrors' => true];

	update_calc_fields('enrollment', $data['selectedID'], calculated_fields()['enrollment']);

	// hook: enrollment_after_update
	if(function_exists('enrollment_after_update')) {
		$res = sql("SELECT * FROM `enrollment` WHERE `stid`='{$data['selectedID']}' LIMIT 1", $eo);
		if($row = db_fetch_assoc($res)) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['stid'];
		$args = ['old_data' => $old_data];
		if(!enrollment_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update ownership data
	sql("UPDATE `membership_userrecords` SET `dateUpdated`='" . time() . "' WHERE `tableName`='enrollment' AND `pkValue`='" . makeSafe($selected_id) . "'", $eo);
}

